/* eslint-env node */
// This file is auto-generated by scripts/generate-variables-css.js
// Run via: node scripts/generate-variables-css.js
// Wired into build via package.json "generate:variables-css" script

import { readFileSync, writeFileSync, existsSync } from 'fs';
import { join, dirname } from 'path';
import { fileURLToPath } from 'url';

const __dirname = dirname(fileURLToPath(import.meta.url));
const root = join(__dirname, '..');

const variablesPath = join(root, 'src/styles/variables.css');
const fontsPath = join(root, 'src/styles/fonts.css');
const globalPath = join(root, 'src/styles/global.css');
const outputCSSPath = join(root, 'src/styles/output.css');
const targetPath = join(root, 'src/styles/modus-wc-variables.css');

const read = (path, label) => {
  if (!existsSync(path)) {
    console.error(`Missing required file: ${label} (${path})`); // eslint-disable-line no-undef
    process.exit(1); // eslint-disable-line no-undef
  }
  return readFileSync(path, 'utf8');
};

const variablesCSS = read(variablesPath, 'variables.css');
const fontsCSS = read(fontsPath, 'fonts.css');
const globalCSS = read(globalPath, 'global.css');
const outputCSS = read(outputCSSPath, 'output.css');

// Extract [data-theme] blocks from output.css (DaisyUI oklch tokens + config vars per theme)
// output.css uses unquoted selectors e.g. [data-theme=connect-light]{...}
const extractOutputThemeBlocks = (css) => {
  const themeNames = [
    'modus-modern-light',
    'modus-modern-dark',
    'modus-classic-light',
    'modus-classic-dark',
    'connect-light',
    'connect-dark',
  ];

  const result = {};

  for (const theme of themeNames) {
    // Match minified [data-theme=theme-name]{...} blocks
    const regex = new RegExp(`\\[data-theme=${theme}\\]\\{([^}]*)\\}`, 'g');
    const match = regex.exec(css);
    if (match) {
      // Extract only CSS custom property declarations
      const vars = match[1]
        .split(';')
        .map((s) => s.trim())
        .filter((s) => s.startsWith('--'))
        .map((s) => `  ${s};`)
        .join('\n');
      result[theme] = vars;
    }
  }

  return result;
};

// Extract only the :root block from global.css theme overrides for each theme
// These use quoted selectors e.g. [data-theme='connect-light']:root { ... }
const extractGlobalThemeBlocks = (css) => {
  const result = {};
  const themeNames = [
    'modus-modern-light',
    'modus-modern-dark',
    'modus-classic-light',
    'modus-classic-dark',
    'connect-light',
    'connect-dark',
  ];

  for (const theme of themeNames) {
    const regex = new RegExp(
      `\\[data-theme=['"]${theme}['"]\\]:root\\s*\\{([^}]*)\\}`,
      's'
    );
    const match = regex.exec(css);
    if (match) {
      result[theme] = match[1].trim();
    }
  }

  return result;
};

const outputThemeVars = extractOutputThemeBlocks(outputCSS);
const globalThemeBlocks = extractGlobalThemeBlocks(globalCSS);

const themeOrder = [
  { name: 'modus-modern-light', comment: '/* Modus Modern Themes */' },
  { name: 'modus-modern-dark', comment: null },
  { name: 'modus-classic-light', comment: '\n/* Modus Classic Themes */' },
  { name: 'modus-classic-dark', comment: null },
  { name: 'connect-light', comment: '\n/* Connect Themes */' },
  { name: 'connect-dark', comment: null },
];

const themeBlocks = themeOrder
  .map(({ name, comment }) => {
    const globalVars = (globalThemeBlocks[name] || '')
      .split('\n')
      .map((l) => l.trim())
      .filter(Boolean)
      .map((l) => `  ${l}`)
      .join('\n');

    const daisyVars = (outputThemeVars[name] || '')
      .split('\n')
      .map((l) => l.trim())
      .filter(Boolean)
      .map(
        (l) =>
          `  ${l.replace(/^(--[^:]+):/, '$1: ').replace(/:\s*\.(\d)/g, ': 0.$1')}`
      )
      .join('\n');

    const body = [globalVars, daisyVars].filter(Boolean).join('\n\n');

    return [
      comment ? `${comment}\n` : '',
      `[data-theme='${name}']:root {`,
      body,
      '}',
    ]
      .filter((s) => s !== '')
      .join('\n');
  })
  .join('\n\n');

const output = `/**
 * Modus Web Components - Variables Only
 *
 * Lightweight alternative to modus-wc-styles.css for legacy apps.
 * Contains ONLY CSS variables, theme definitions, and font declarations.
 * No Tailwind reset, no DaisyUI classes, no utility classes.
 *
 * Use this when:
 * - Your app uses Modus components inside Shadow DOM
 * - You want to avoid the Tailwind Preflight reset causing style regressions
 * - The handleShadowDOMStyles() injection handles class rules inside shadow roots
 *
 * Usage:
 *   import '@trimble-oss/moduswebcomponents/modus-wc-variables.css';
 */

/* ===== Font Declarations ===== */

${fontsCSS.trim()}

/* ===== CSS Variables ===== */

${variablesCSS.trim()}

/* ===== Theme Overrides ===== */

${themeBlocks}
`;

writeFileSync(targetPath, output, 'utf8');

console.log(`Generated: ${targetPath}`); // eslint-disable-line no-undef
